"""
Unit tests to validate SEO audit report for VoltDrive website.

These tests check whether the agent's SEO report correctly identifies
the intentional SEO issues planted in the ev_website files.

Usage:
    pytest seo_test.py -v

The tests expect an SEO report file (seo_report.md or seo_report.txt)
to exist in the same directory, generated by the agent.
"""

import os
import re
import pytest
from pathlib import Path


def get_report_content():
    """Load the SEO report generated by the agent."""
    report_paths = [
        "seo_report.md",
        "seo_report.txt",
        "seo-report.md",
        "seo-report.txt",
        "report.md",
        "audit_report.md",
        "audit-report.md",
    ]

    current_dir = Path(__file__).parent

    for report_name in report_paths:
        report_path = current_dir / report_name
        if report_path.exists():
            return report_path.read_text().lower()

    # Also check for any .md file that might be the report
    md_files = list(current_dir.glob("*.md"))
    for md_file in md_files:
        content = md_file.read_text().lower()
        if "seo" in content or "audit" in content or "title" in content:
            return content

    pytest.fail("No SEO report file found. Expected seo_report.md or similar.")


@pytest.fixture
def report():
    """Fixture that provides the report content."""
    return get_report_content()


class TestIndexPageIssues:
    """Tests for SEO issues in index.html."""

    def test_identifies_short_title(self, report):
        """index.html has title 'VoltDrive' which is too short (<50 chars)."""
        assert any(term in report for term in [
            "title too short",
            "title is too short",
            "short title",
            "title length",
            "voltdrive\" (9",  # mentions the short title with char count
            "index.html" and "title",
        ]), "Report should identify that index.html has a title that is too short"

    def test_identifies_short_meta_description(self, report):
        """index.html has meta description 'We sell cars.' which is too short."""
        assert any(term in report for term in [
            "description too short",
            "description is too short",
            "short description",
            "meta description" and "short",
            "we sell cars",
            "description length",
        ]), "Report should identify the meta description is too short"

    def test_identifies_multiple_h1_tags(self, report):
        """index.html has two H1 tags which is bad for SEO."""
        assert any(term in report for term in [
            "multiple h1",
            "two h1",
            "2 h1",
            "more than one h1",
            "duplicate h1",
            "h1 tags",
        ]), "Report should identify multiple H1 tags on index.html"

    def test_identifies_generic_alt_text(self, report):
        """index.html has generic alt text like 'car' on images."""
        assert any(term in report for term in [
            "alt text",
            "alt attribute",
            "image alt",
            "generic alt",
            "descriptive alt",
            "alt=\"car\"",
        ]), "Report should identify generic/missing alt text on images"


class TestModelsPageIssues:
    """Tests for SEO issues in models.html."""

    def test_identifies_missing_brand_in_title(self, report):
        """models.html has title 'Models' without brand name."""
        assert any(term in report for term in [
            "models.html" and "title",
            "missing brand",
            "title" and "models\"",
            "brand name",
            "voltdrive" and "title",
        ]), "Report should identify that models.html title is missing brand name"

    def test_identifies_vague_meta_description(self, report):
        """models.html has vague meta 'Check out our cars'."""
        assert any(term in report for term in [
            "check out our cars",
            "vague description",
            "generic description",
            "description" and "models",
        ]), "Report should identify vague meta description on models.html"

    def test_identifies_multiple_h1_on_models(self, report):
        """models.html has two H1 tags."""
        assert any(term in report for term in [
            "multiple h1",
            "two h1",
            "2 h1",
            "h1" and "models",
        ]), "Report should identify multiple H1 tags on models.html"


