class TestAboutPageIssues:
    """Tests for SEO issues in about.html."""

    def test_identifies_title_too_long(self, report):
        """about.html has extremely long title (150+ characters)."""
        assert any(term in report for term in [
            "title too long",
            "title is too long",
            "long title",
            "exceeds",
            "truncat",
            "60 character",
            "about" and "title",
        ]), "Report should identify that about.html title is too long"

    def test_identifies_short_meta_description(self, report):
        """about.html has meta 'About VoltDrive' which is too short."""
        assert any(term in report for term in [
            "about voltdrive",
            "description" and "short",
            "meta" and "about",
        ]), "Report should identify short meta description on about.html"

    def test_identifies_markdown_in_html(self, report):
        """about.html has '# About VoltDrive' markdown instead of <h1>."""
        # This is a tricky one - the agent might notice the broken H1
        assert any(term in report for term in [
            "markdown",
            "# about",
            "missing h1",
            "no h1",
            "h1 tag",
            "heading",
        ]), "Report should identify the broken/missing H1 on about.html"


