class TestReportCompleteness:
    """Tests to ensure the report is comprehensive."""

    def test_report_covers_multiple_pages(self, report):
        """Report should analyze multiple pages, not just one."""
        pages_mentioned = sum([
            "index" in report,
            "models" in report,
            "technology" in report,
            "charging" in report,
            "about" in report,
            "contact" in report,
        ])
        assert pages_mentioned >= 3, f"Report should cover at least 3 pages, found {pages_mentioned}"

    def test_report_includes_recommendations(self, report):
        """Report should include fix recommendations."""
        assert any(term in report for term in [
            "recommend",
            "suggestion",
            "should",
            "fix",
            "improve",
            "change",
            "update",
        ]), "Report should include recommendations for fixing issues"

    def test_report_mentions_title_issues(self, report):
        """Report should discuss title tag issues."""
        assert "title" in report, "Report should analyze title tags"

    def test_report_mentions_meta_description_issues(self, report):
        """Report should discuss meta description issues."""
        assert any(term in report for term in [
            "meta description",
            "description",
            "meta",
        ]), "Report should analyze meta descriptions"

    def test_report_mentions_heading_issues(self, report):
        """Report should discuss heading structure (H1, H2, etc.)."""
        assert any(term in report for term in [
            "h1",
            "heading",
            "header",
        ]), "Report should analyze heading structure"


class TestTechnologyPageAsPositiveExample:
    """technology.html is intentionally well-optimized as a control."""

    def test_technology_page_recognized_as_good(self, report):
        """technology.html should be recognized as having good SEO."""
        # This is a softer test - we just want to make sure if technology
        # is mentioned, it's not flagged as severely as others
        if "technology" in report:
            # If technology is mentioned with issues, they should be minor
            tech_section = report[report.find("technology"):report.find("technology")+500]
            severe_issues = sum([
                "too short" in tech_section,
                "too long" in tech_section,
                "missing" in tech_section,
                "multiple h1" in tech_section,
            ])
            assert severe_issues <= 1, "technology.html should have fewer issues than other pages"


# Summary test that gives an overall pass/fail
class TestOverallAuditQuality:
    """Meta-tests for overall audit quality."""

    def test_minimum_issues_identified(self, report):
        """Report should identify at least 5 distinct issues."""
        issues_found = 0

        issue_indicators = [
            "title" and ("short" in report or "long" in report),
            "description" and "short" in report,
            "multiple h1" in report or "h1" in report,
            "alt text" in report or "alt=" in report,
            "click here" in report,
            "anchor text" in report,
            "keyword" in report,
            "internal link" in report,
            "missing" in report,
        ]

        issues_found = sum([1 for indicator in issue_indicators if indicator])

        assert issues_found >= 5, f"Report should identify at least 5 issues, found indicators for {issues_found}"


